 {"id":"bd-n0kg","title":"Implement cancellation conformance tests","description":"## Overview

Implement conformance tests for the cancellation protocol: request, drain, finalize phases.

## Test Cases

### Cancel Request Propagation
```rust
conformance_test!(cancel_propagates_to_children, |cx| {
    let child_cancelled = Arc::new(AtomicBool::new(false));
    let child_cancelled2 = child_cancelled.clone();

    cx.region(|child_cx| {
        child_cx.spawn(async move {
            loop {
                if cx.is_cancelled() {
                    child_cancelled2.store(true, Ordering::SeqCst);
                    return;
                }
                yield_now().await;
            }
        });

        // Cancel parent
        cx.cancel(CancelReason::User);
    });

    assert!(child_cancelled.load(Ordering::SeqCst));
});
```

### Drain Phase
```rust
conformance_test!(cancel_allows_drain_phase, |cx| {
    let drained = Arc::new(AtomicBool::new(false));
    let drained2 = drained.clone();

    cx.region(|child_cx| {
        child_cx.spawn(async move {
            // Wait for cancellation
            cx.cancellation().await;

            // Drain phase: cleanup work
            cleanup_resources();
            drained2.store(true, Ordering::SeqCst);
        });

        cx.cancel(CancelReason::User);
    });

    // Drain phase must have completed
    assert!(drained.load(Ordering::SeqCst));
});
```

### Cancel Does Not Lose Data
```rust
conformance_test!(cancel_does_not_lose_committed_data, |cx| {
    let (tx, rx) = channel();

    cx.region(|child_cx| {
        child_cx.spawn(async move {
            // Reserve
            let permit = tx.reserve().await.unwrap();

            // Commit
            permit.send(42);
        });

        // Cancel after send started
        cx.cancel(CancelReason::User);
    });

    // Data must not be lost
    assert_eq!(rx.recv().await, Some(42));
});
```

### Cancel Reason Attribution
```rust
conformance_test!(cancel_reason_is_available, |cx| {
    let reason_seen = Arc::new(Mutex::new(None));
    let reason_seen2 = reason_seen.clone();

    cx.region(|child_cx| {
        child_cx.spawn(async move {
            cx.cancellation().await;
            *reason_seen2.lock().unwrap() = Some(cx.cancel_reason());
        });

        cx.cancel(CancelReason::Deadline);
    });

    assert_eq!(*reason_seen.lock().unwrap(), Some(CancelReason::Deadline));
});
```

### Nested Cancellation
```rust
conformance_test!(nested_cancel_propagates_correctly, |cx| {
    cx.region(|cx1| {
        cx1.region(|cx2| {
            cx2.region(|cx3| {
                // Cancel middle region
                cx2.cancel(CancelReason::User);

                // cx3 should be cancelled
                assert!(cx3.is_cancelled());

                // cx1 should NOT be cancelled
                assert!(!cx1.is_cancelled());
            });
        });
    });
});
```

